mapper.select:
SELECT id, notice_title, notice_type, notice_content, status, create_by, create_time, update_by, update_time FROM sys_notice WHERE del_flag = '0'
AND notice_title LIKE CONCAT('%', #{query.noticeTitle}, '%')
AND notice_type = #{query.noticeType}
AND status = #{query.status}
ORDER BY create_time DESC
